/* Return the largest sum of any contiguous subarray in the vector x.
   The implementation uses Kadane's algorithm (O(n)) which preserves the
   exact behavior of the original double‑loop but is much faster. 
*/
int maximumSubarray(std::vector<int> const& x) {
    int best = std::numeric_limits<int>::lowest();
    int cur  = 0;
    for (int v : x) {
        cur += v;
        if (cur > best) best = cur;
        if (cur < 0) cur = 0;          // reset when sum becomes negative
    }
    /* If all numbers are negative, best was updated during the loop,
       but cur would have been reset to 0. The above logic handles this case. */
    return best;
}
