/* Count the number of doubles in the vector `x` that have a fractional
   part in [0, 0.25), [0.25, 0.5), [0.5, 0.75), and [0.75, 1).
   The results are accumulated in `bins`.
   The implementation is thread‑safe and exploits data‑parallelism. */
void countQuartiles(std::vector<double> const& x, std::array<std::size_t, 4>& bins)
{
    /* Initialize result array */
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

