inline int smallestOdd(std::vector<int> const& x) {
    // Fast path for empty or very small vectors
    if (x.empty()) return std::numeric_limits<int>::max();

    // Parallel scan: each thread keeps a local minimum odd value
    int global_min = std::numeric_limits<int>::max();

    // OpenMP parallel for with reduction on a custom struct
    #pragma omp parallel for reduction(min:global_min)
    for (std::size_t i = 0; i < x.size(); ++i) {
        int val = x[i];
        // Only consider odd numbers
        if ((val & 1) && val < global_min) {
            global_min = val;
        }
    }
    return global_min;
