```cpp
#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Compute Y = A * X
 * A is MxK sparse (COO), X is KxN sparse (COO), Y is dense MxN (row‑major).
 * The implementation uses a hash map for X and parallelizes the outer loop over A.
 */
static inline void spmm(std::vector<COOElement> const& A,
                        std::vector<COOElement> const& X,
                        std::vector<double> &Y,
                        size_t M, size_t K, size_t N)
{
    // build a hash map from X.row -> list of (col, value)
    std::unordered_map<size_t, std::vector<std::pair<size_t,double>>> row_to_cols;
    row_to_cols.reserve(X.size()*2);
    for (auto const& e : X)
        row_to_cols[e.row].emplace_back(e.column, e.value);

    Y.assign(M * N, 0.0);

    // parallel over rows of A
    ^#pragma omp parallel for schedule(dynamic)
    for (size_t i = 0; i < A.size(); ++i) {
        auto const& a = A[i];
        auto it = row_to_cols.find(a.column);
        if (it == row_to_cols.end()) continue;
        const auto &vec = it->second;
        size_t base = a.row * N;
        for (auto const& [col, val] : vec) {
            #pragma omp atomic
            Y[base + col] += a.value * val;
        }
    }
}
