#include <omp.h>

/* In the vector x negate the odd values and divide the even values by 2.
   Example:

   input: [16, 11, 12, 14, 1, 0, 5]
   output: [8, -11, 6, 7, -1, 0, -5]
*/
inline void negateOddsAndHalveEvens(std::vector<int> &x)
{
    // If the vector is empty we can return immediately
    const size_t n = x.size();
    if (n == 0) return;

    int *data = x.data();

    // Use OpenMP to parallelise the loop over available threads.
    // Static scheduling gives a good balance for predictable workloads.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < n; ++i)
    {
        // Determine parity without a branch on __int128.
        // For odd numbers (i & 1) is true; for even it is false.
        int val = data[i];
        if (val & 1)               // odd
            data[i] = -val;        // negate
        else
            data[i] = val >> 1;    // arithmetic shift is equivalent to division by 2 for evens
    }
}
