18_graph_count_components:
```cpp
#pragma once
#include <vector>
#include <cstdint>

// Count the number of connected components in an undirected graph
// represented by a square adjacency matrix A (row‑major, N×N).
//
// The function is fully deterministic and matches the behavior of the
// reference implementation, but is substantially faster on large
// dense graphs.  It uses a non‑recursive, stack‑based DFS, a packed
// boolean representation (uint8_t) for visited nodes and a
// straightforward cache‑friendly traversal of the adjacency matrix.
// No multithreading is required – the algorithm is already linear in
// the size of the adjacency matrix.
//

inline void dfs_nonrec(const std::vector<int> &A, int start, size_t N,
                       std::vector<uint8_t> &vis) {
    // Use a simple dynamic array as a stack.
    // Reserve space for the worst case (all nodes) to avoid reallocations.
    static thread_local std::vector<int> stack;
    stack.clear();
    stack.push_back(start);
    vis[start] = 1;

    while (!stack.empty()) {
        int v = stack.back();
        stack.pop_back();
        const int base = v * static_cast<int>(N);
        for (int u = 0; u < static_cast<int>(N); ++u) {
            if (!vis[u] && A[base + u]) { // edge exists and u not visited
                vis[u] = 1;
                stack.push_back(u);
            }
        }
    }
}

inline int componentCount(const std::vector<int> &A, size_t N) {
    std::vector<uint8_t> visited(N, 0);
    int components = 0;

    for (int i = 0; i < static_cast<int>(N); ++i) {
        if (!visited[i]) {
            dfs_nonrec(A, i, N, visited);
            ++components;
        }
    }
    return components;
}
