#pragma once
#include <vector>
#include <limits>
#include <cstddef>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A (row‑major, N × N).  The graph is guaranteed
   to be connected, undirected and unweighted.  The function retains the exact
   semantics of the original implementation but is optimized for speed.
*/
inline int shortestPathLength(const std::vector<int>& A, size_t N,
                               int source, int dest)
{
    /* Use a byte per vertex for visited flags – faster than bool vector
       due to better cache friendliness on x86‑64. */
    std::vector<unsigned char> visited(N, 0);
    /* Allocate a simple circular buffer for the BFS queue.  Two arrays keep
       the vertex indices and their corresponding distances.  Using raw
       vectors eliminates the overhead of std::queue/ std::pair. */
    std::vector<int> q(N);
    std::vector<int> dist(N, 0);

    size_t head = 0, tail = 0;
    visited[source] = 1;
    q[tail] = source;
    dist[tail] = 0;
    ++tail;

    while (head != tail) {
        const int cur = q[head];
        const int curDist = dist[head];
        ++head;           // pop

        if (cur == dest) return curDist;

        const int rowOffset = cur * static_cast<int>(N);
        for (int nxt = 0; nxt < static_cast<int>(N); ++nxt) {
            if (A[rowOffset + nxt] && !visited[nxt]) {
                visited[nxt] = 1;
                q[tail] = nxt;
                dist[tail] = curDist + 1;
                ++tail;
            }
        }
    }
    return std::numeric_limits<int>::max(); // unreachable in connected graph
}
