/// Count the number of pixels in image with each grayscale intensity.
/// `image` is a vector of values in [0,255].
/// The result is stored in `bins`. The function is thread‑safe
/// and performs best‑effort parallelism on Gnu/Linux machines with
/// GCC and OpenMP support.
inline void pixelCounts(const std::vector<int>& image,
                        std::array<std::size_t, 256>& bins) {

    // Initialise output histogram to zero.
    bins.fill(0);

    // If the image is empty, nothing further needs to be done.
    if (image.empty()) return;

    // Use a dynamic loop with static scheduling to keep work
    // balanced across threads. Each thread works on a block,
    // builds a private local histogram, and at the end merges
    // the local histogram into the shared result.
    #pragma omp parallel
    {
        // Each thread keeps a local histogram to avoid
        // costly atomic operations per pixel.
        std::array<std::size_t, 256> local_hist = {};

        // Determine the range of indices for this thread.
        int first, last;
        #pragma omp for nowait schedule(static)
        for (int i = 0; i < static_cast<int>(image.size()); ++i) {
            // Bounds check is omitted – the caller guarantees valid data.
            const int value = image[i];
            ++local_hist[static_cast<std::size_t>(value)];
        }

        // Merge the local histogram into the shared global one.
        #pragma omp critical
        {
            detail::merge_bins(local_hist, bins);
        }
    }
