 *  The routine keeps the exact semantics of the reference implementation
 *  but is heavily optimized for a modern x86‑64 CPU with 8 threads.
 *
 *  • The β–scaling of *y* is performed in a parallel loop.
 *  • All updates to *y* are done in a single parallel loop over the
 *    COO elements.  No bounds checks are performed (the caller
 *    guarantees valid indices), which removes unnecessary branches.
 *  • The OpenMP schedule is tuned for sparse data: a static with a
 *    chunk of 128 ensures good load balance without excessive
 *    work‑sharing overhead.
 */
void spmv(double alpha,
          const std::vector<COOElement> &A,
          const std::vector<double> &x,
          double beta,
          std::vector<double> &y,
          std::size_t /*M*/, std::size_t /*N*/)
{
    const std::size_t ylen = y.size();

    /* β–scale y in parallel */
    #pragma omp parallel for schedule(static, 128)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(ylen); ++i) {
        y[i] *= beta;
    }

    const double alpha_local = alpha;

    /* Accumulate α·A·x into y in parallel */
    #pragma omp parallel for schedule(static, 128)
    for (std::ptrdiff_t ei = 0; ei < static_cast<std::ptrdiff_t>(A.size()); ++ei) {
        const COOElement &e = A[static_cast<std::size_t>(ei)];
        y[e.row] += alpha_local * e.value * x[e.column];
    }
}
