/**
 * Direct O(N²) Discrete Fourier Transform.
 * Preserves the exact behaviour of the original implementation.
 *
 * @param x      Input real sequence.
 * @param output Output complex sequence; resized internally to match input size.
 */
inline void dft(const std::vector<double> &x,
                std::vector<std::complex<double>> &output)
{
    const int N = static_cast<int>(x.size());
    output.resize(N);
    const double two_pi = 2.0 * M_PI;

    // Pointers for fast access
    const double *xp = x.data();
    std::complex<double> *op = output.data();

    // Parallelise over the output index k
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k)
    {
        const double angle_k = two_pi * k / N;
        std::complex<double> sum(0.0, 0.0);

        for (int n = 0; n < N; ++n)
        {
            const double theta = angle_k * n;
            const double c_re = std::cos(theta);
            const double c_im = -std::sin(theta); // Euler's formula with a minus sign
            sum += xp[n] * std::complex<double>(c_re, c_im);
        }

        op[k] = sum;
    }
}
