   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
double closestPair(std::vector<double> const& x) {
    const std::size_t n = x.size();
    if (n < 2) return 0.0;

    /* Work on a sorted copy – the minimum pair is always adjacent in a
       sorted list. */
    std::vector<double> sorted(x);
    std::sort(sorted.begin(), sorted.end(), [](double a, double b){ return a < b; });

    /* Parallel reduction over the (n‑1) adjacent differences. */
    double minDist = std::numeric_limits<double>::max();

    #pragma omp parallel for reduction(min:minDist)
    for (std::size_t i = 0; i + 1 < n; ++i) {
        const double d = std::abs(sorted[i+1] - sorted[i]);
        if (d < minDist) minDist = d;
    }

    return minDist;
}
