*/
int findKthSmallest(std::vector<int> const& x, int k) {
    // copy to allow mutation
    std::vector<int> temp = x;
    // nth_element places the element that would be at index k-1
    // of a sorted array in that position, all smaller elements before,
    // all larger elements after.
