#pragma once
#include <vector>
#include <cstdlib>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row;
    size_t column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format.
   x and b are dense vectors with N elements.
   The implementation keeps the original algorithmic behaviour but replaces
   the 2‑dimensional std::vector matrix with a single contiguous 1‑D vector
   and parallelises the innermost loops with OpenMP.  This gives a
   significant speed‑up on multi‑core machines while staying exactly
   equivalent to the reference solver. */
void solveLinearSystem(
    const std::vector<COOElement> &A,
    const std::vector<double> &b,
    std::vector<double> &x,
    size_t N)
{
    /* contiguous dense matrix in row major order */
    std::vector<double> matrix(N * N, 0.0);
    std::vector<double> b_copy = b;

    /* fill the matrix */
    for (const auto &e : A) {
        matrix[e.row * N + e.column] = e.value;
    }

    x.assign(N, 0.0);

    /* Gaussian elimination */
    for (size_t i = 0; i < N; ++i) {
        /* pivot search */
        size_t maxRow = i;
        double maxEl = std::fabs(matrix[i * N + i]);
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::fabs(matrix[k * N + i]);
            if (val > maxEl) {
                maxEl = val;
                maxRow = k;
            }
        }

        /* swap rows i and maxRow */
        if (maxRow != i) {
            for (size_t k = i; k < N; ++k) {
                std::swap(matrix[maxRow * N + k], matrix[i * N + k]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        /* eliminate rows below */
        for (size_t k = i + 1; k < N; ++k) {
            double c = -matrix[k * N + i] / matrix[i * N + i];
            /* parallelise the column loop */
#pragma omp parallel for schedule(static)
            for (size_t j = i; j < N; ++j) {
                if (i == j) {
                    matrix[k * N + j] = 0.0;
                } else {
                    matrix[k * N + j] += c * matrix[i * N + j];
                }
            }
            b_copy[k] += c * b_copy[i];
        }
    }

    /* back substitution */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        x[i] = b_copy[i] / matrix[i * N + i];
        for (int k = i - 1; k >= 0; --k) {
            b_copy[k] -= matrix[k * N + i] * x[i];
        }
    }
}
