/*
 * Sort the vector x of complex numbers by their magnitude in ascending order.
 * This implementation avoids computing the expensive square root inside the
 * comparison by comparing the squared magnitudes instead of the actual
 * magnitudes. The result is the same ordering, but the comparison is faster.
 */
void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    // Comparator that compares squared magnitudes
    auto cmp = [](const std::complex<double>& a, const std::complex<double>& b) noexcept
    {
        const double aa = a.real() * a.real() + a.imag() * a.imag();
        const double bb = b.real() * b.real() + b.imag() * b.imag();
        return aa < bb;
    };

    std::sort(x.begin(), x.end(), cmp);
}
