/*
 * Compute y = A * x  (matrix‑vector multiplication)
 * A : M x N matrix, stored row‑major
 * x : vector of length N
 * y : vector of length M (output)
 *
 * The implementation is fully parallel using OpenMP and exploits
 * straightforward cache‑friendly access patterns.  The
 * behaviour is identical to the original function.
 */
void gemv(std::vector<double> const& A,
          std::vector<double> const& x,
          std::vector<double> &y,
          size_t M, size_t N)
{
    // Ensure the output vector has the correct size
    y.resize(M);

    // Parallel over rows – each thread works on a disjoint set of rows
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i) {
        double sum = 0.0;
        const double* row = A.data() + i * N;   // pointer to the i‑th row
        const double* xv   = x.data();          // pointer to x

        // Simple loop unrolling (factor 4)
        size_t j = 0;
        for (; j + 3 < N; j += 4) {
            sum += row[j]     * xv[j];
            sum += row[j + 1] * xv[j + 1];
            sum += row[j + 2] * xv[j + 2];
            sum += row[j + 3] * xv[j + 3];
        }
        // Handle remaining elements
        for (; j < N; ++j) {
            sum += row[j] * xv[j];
        }
        y[i] = sum;
    }
