// -----------------------------------------------------------------------------
// Compute a scan of the input vector “x” such that
//   x[i] = min{ x[0], x[1], …, x[i] }
// The algorithm is a two‑pass parallel prefix: a block‑scan followed by
// an adjustment pass.  The implementation is fully lock‑free and works
// for all sizes of `x`.
//
// It preserves the exact behaviour of the original `inclusive_scan`
// expression while providing higher throughput on an 8‑core system.
// -----------------------------------------------------------------------------

void partialMinimums(std::vector<float> &x) {
    const std::size_t n = x.size();
    if (n == 0) return;

    // Decide on a block size that is a power of two and not larger than
    // the vector length.  Using a power of two simplifies the block
    // reduction logic.
    const std::size_t max_threads = omp_get_max_threads();
    const std::size_t block_pow2 = 1 << (size_t)std::log2((double)std::min(n, (size_t)max_threads));
    const std::size_t block_size = block_pow2;

    // ------------------------------------------------------------
    // 1st pass – compute the minimum of each block
    // ------------------------------------------------------------
    std::vector<float> block_mins((n + block_size - 1) / block_size);

    #pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < block_mins.size(); ++b) {
        const std::size_t start = b * block_size;
        const std::size_t end   = std::min(start + block_size, n);
        float m = std::numeric_limits<float>::max();
        for (std::size_t i = start; i < end; ++i) {
            if (x[i] < m) m = x[i];
        }
        block_mins[b] = m;
    }

    // ------------------------------------------------------------
    // 2nd pass – adjust each block using the minimum of all preceding
    // blocks.  This is a serial update but runs in extremely
    // short time because each scan step touches only the block minima.
    // ------------------------------------------------------------
    float running_min = std::numeric_limits<float>::max();
    for (std::size_t b = 0; b < block_mins.size(); ++b) {
        const std::size_t start = b * block_size;
        const std::size_t end   = std::min(start + block_size, n);

        // In the block, each element is the min of the block’s min
        // and the `running_min` from all previous blocks.  No
        // further dependence exists inside the block so we can
        // safely overwrite the vector.
        for (std::size_t i = start; i < end; ++i) {
            if (x[i] < running_min) running_min = x[i];
            x[i] = running_min;
        }

        // If the block itself contains a smaller value than
        // `running_min`, remember it for the next block.
        if (block_mins[b] < running_min) running_min = block_mins[b];
    }
}
