struct Point {
    double x, y;
};

/*
 * Count the number of cartesian points in each quadrant.
 * The vector `points` contains a list of `Point` objects.
 * Store the counts in `bins` (bins[0] -> Q0, bins[1] -> Q1,
 *                           bins[2] -> Q2, bins[3] -> Q3).
 *
 * The implementation uses a lightweight branch‑free path
 * and a parallel reduction over the input data.
 */
void countQuadrants(std::vector<Point> const& points, std::array<size_t, 4>& bins) {
    // Reset the output bins.
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Number of threads we will use. GCC/Clang will honor the environment variable OMP_NUM_THREADS.
    const int nr_threads = 8;  // we prefer 8 but will fallback if not enough hardware threads
    const int n = static_cast<int>(points.size());

    if (n == 0) return;

    // Allocate per-thread local accumulators.
    std::vector<std::array<size_t,4>> local_bins(nr_threads);
    for (auto& lb : local_bins) lb.fill(0);

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const Point& p = points[i];
        // determine quadrant (branchless)
        const size_t bx = p.x < 0.0 ? 1u : 0u;  // 1 if x<0
        const size_t by = p.y < 0.0 ? 1u : 0u;  // 1 if y<0
        // mapping: (bx,by) -> idx
        // (0,0)->0, (1,0)->1, (1,1)->2, (0,1)->3
        const size_t idx = (bx << 1) | by;
        size_t thread_idx = omp_get_thread_num();
        local_bins[thread_idx][idx] += 1;
    }

    // Reduce per-thread results into the final bins.
    for (int t = 0; t < nr_threads; ++t) {
        bins[0] += local_bins[t][0];
        bins[1] += local_bins[t][1];
        bins[2] += local_bins[t][2];
        bins[3] += local_bins[t][3];
    }
}
