    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

// 2‑D cross product (b‑a) × (c‑a)
inline double cross(Point const& a, Point const& b, Point const& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

// Computes the perimeter of the smallest convex polygon enclosing all points
double convexHullPerimeter(std::vector<Point> const& points) {
    if (points.size() < 3) return 0.0;

    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end());           // sort by x then y

    std::vector<Point> hull(2 * pts.size());     // maximum possible size
    int k = 0;

    // Lower hull
    for (size_t i = 0; i < pts.size(); ++i) {
        while (k >= 2 && cross(hull[k-2], hull[k-1], pts[i]) <= 0) k--;
        hull[k++] = pts[i];
    }
    // Upper hull
    for (size_t i = pts.size(); i-- > 0;) {
        while (k >= (int)pts.size() + 1 && cross(hull[k-2], hull[k-1], pts[i]) <= 0) k--;
        hull[k++] = pts[i];
    }

    hull.resize(k - 1);        // last point duplicates first

    double perim = 0.0;
#pragma omp parallel for reduction(+:perim) schedule(static)
    for (int i = 0; i < (int)hull.size(); ++i) {
        int j = (i + 1) % (int)hull.size();
        perim += dist(hull[i], hull[j]);
    }
    return perim;
}
