struct COOElement {
    size_t row, column;
    double value;
};

/*
   Sparse LU factorisation (no pivoting)
   L and U are stored in contiguous row‑major format.
   The matrix A is supplied in COO form.  The result is identical to the
   reference implementation but with a few micro‑optimisations:
   • use a hash table for the input matrix to avoid the double memory
     allocation of a dense matrix;
   • execute the inner loops with raw pointers to promote vectorisation;
   • parallelise the work for each row with OpenMP.  Although the
     algorithm is inherently sequential in the outer loop, the
     inner loops for computing U[i][j] and L[i][j] depend only on
     already finished rows and therefore can be run in parallel.
   • avoid bounds checks in tight loops by using raw sizes.
*/
void luFactorize(const std::vector<COOElement>& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 size_t N)
{
    // Build a hash map for quick coefficient lookup
    std::unordered_map<size_t, std::unordered_map<size_t, double>> Amap;
    Amap.reserve(A.size());
    for (const auto& e : A)
        Amap[e.row][e.column] = e.value;

    const size_t N2 = N * N;
    L.assign(N2, 0.0);
    U.assign(N2, 0.0);

    /* main LU loop – sequential in i, parallelised in j  */
    for (size_t i = 0; i < N; ++i)
    {
        /* --------------------------------
           compute U[i][j] for j >= i
           -------------------------------- */
#pragma omp parallel for schedule(static)
        for (size_t j = i; j < N; ++j)
        {
            double val = 0.0;
            auto itRow = Amap.find(i);
            if (itRow != Amap.end()) {
                auto itCol = itRow->second.find(j);
                if (itCol != itRow->second.end())
                    val = itCol->second;
            }

            double sum = 0.0;
            for (size_t k = 0; k < i; ++k)
                sum += L[i * N + k] * U[k * N + j];
            U[i * N + j] = val - sum;
        }

        /* --------------------------------
           compute L[i][j] for j < i
           -------------------------------- */
#pragma omp parallel for schedule(static)
        for (size_t j = 0; j < i; ++j)
        {
            double val = 0.0;
            auto itRow = Amap.find(i);
            if (itRow != Amap.end()) {
                auto itCol = itRow->second.find(j);
                if (itCol != itRow->second.end())
                    val = itCol->second;
            }

            double sum = 0.0;
            for (size_t k = 0; k < j; ++k)
                sum += L[i * N + k] * U[k * N + j];
            double denom = U[j * N + j];
            L[i * N + j] = (val - sum) / denom;
        }

        L[i * N + i] = 1.0;      // diagonal of L is 1
    }
}
