        std::size_t rBit = 0;
        for (std::size_t j = 0; j < m; ++j) {
            rBit = (rBit << 1) | (v & 1);
            v >>= 1;
        }
        rev[i] = rBit;
    }
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i)
            std::swap(data[i], data[j]);
    }

    // FFT butterfly stages
    for (std::size_t s = 1; s <= m; ++s) {
        const std::size_t m2 = 1 << s;
        const std::size_t half = m2 >> 1;
        const std::size_t step = N / m2;
        const std::complex<double>* wtab = w.data() + (N / m2) * step;

        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m2) {
            for (std::size_t j = 0; j < half; ++j) {
                std::size_t idx1 = k + j;
                std::size_t idx2 = idx1 + half;
                std::complex<double> t = wtab[j] * data[idx2];
                data[idx2] = data[idx1] - t;
                data[idx1] += t;
            }
        }
    }

    // Output real and imag parts
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = data[j].real();
        i[j] = data[j].imag();
    }
}
