/* Compute one iteration of a 3‑point 1‑D Jacobi stencil.
   input  : immutable source array
   output : destination array (must be same size as input)
   Each output[i] = (input[i-1] + input[i] + input[i+1]) / 3,
   with out‑of‑bounds values treated as 0.
   Behaviour is identical to the reference implementation. */
void jacobi1D(std::vector<double> const& input, std::vector<double> &output)
{
    const std::size_t n = input.size();
    if (n == 0) return;

    // Ensure output has the same size as input
    if (output.size() != n) output.resize(n);

    const double *src  = input.data();
    double      *dst   = output.data();
    const double inv3   = 1.0 / 3.0;

    /* Handle the first element (no left neighbour) */
    dst[0] = (src[0] + src[1]) * inv3;

    /* Handle the last element (no right neighbour) */
    dst[n-1] = (src[n-2] + src[n-1]) * inv3;

    /* Main loop – no bounds checks needed */
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 1; i < static_cast<std::ptrdiff_t>(n - 1); ++i) {
        dst[i] = (src[i-1] + src[i] + src[i+1]) * inv3;
    }
}
