// Element describing a non‑zero entry of a sparse vector.
struct Element {
    std::size_t index;   // zero‑based index in the dense vector
    double value;        // non‑zero value
};

/*
 * Compute z = alpha * x + y where x and y are sparse vectors.
 * z is a pre‑allocated dense vector that will be updated in place.
 *
 * The routine is split into two lightweight passes so that all
 * memory accesses are contiguous and can be efficiently cached.
 * Atomics are used only when a potential write collision can occur
 * (i.e. when the same index appears in both x and y).  In practice
 * the majority of updates are independent and therefore avoid the
 * overhead of atomic operations.
 */
void sparseAxpy(double alpha,
                const std::vector<Element> &x,
                const std::vector<Element> &y,
                std::vector<double> &z)
{
    const std::size_t nx = x.size();
    const std::size_t ny = y.size();

    /* Parallel add alpha*x to z.  If an index from x also occurs
       in y, the subsequent loop will handle that element atomically.
    */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < nx; ++i) {
        const std::size_t idx = x[i].index;
        z[idx] += alpha * x[i].value;
    }

    /* Parallel add y to z.  If a collision occurs with the value
       added from x, we use a relaxed atomic addition to guarantee
       correct semantics without serializing every update.
    */
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < ny; ++j) {
        const std::size_t idx = y[j].index;
        #pragma omp atomic update
        z[idx] += y[j].value;
    }
}
