/*
  Return true if `val` is only in one of vectors `x` or `y`.
  Return false if it is in both or neither.
*/
inline bool xorContains(std::vector<int> const& x, std::vector<int> const& y, int val)
{
    // Quick checks for empty vectors
    if (x.empty() && y.empty())
        return false;

    // Linear search in the first vector
    bool foundInX = false;
    for (auto const& elem : x)
        if (elem == val) { foundInX = true; break; }

    // Linear search in the second vector
    bool foundInY = false;
    for (auto const& elem : y)
        if (elem == val) { foundInY = true; break; }

    // XOR of the two boolean flags gives the desired result
    return foundInX ^ foundInY;
}
