/* Return the area of the smallest triangle that can be formed using any
   three distinct points from 'points'.  The algorithm is a brute‑force
   O(n³) search but is parallelised with OpenMP so that up to eight
   threads can work on it concurrently.  All computations are done with
   double precision and the result is identical to the serial
   implementation. */
double smallestArea(std::vector<Point> const& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    const double INF = std::numeric_limits<double>::max();
    double minArea = INF;

    #pragma omp parallel for collapse(3) schedule(static) reduction(min:minArea)
    for (std::size_t i = 0; i < n - 2; ++i) {
        for (std::size_t j = i + 1; j < n - 1; ++j) {
            for (std::size_t k = j + 1; k < n; ++k) {
                // shoelace formula, absolute value, half the parallelogram
                double area = 0.5 * std::fabs(
                    points[i].x * (points[j].y - points[k].y) +
                    points[j].x * (points[k].y - points[i].y) +
                    points[k].x * (points[i].y - points[j].y));
                if (area < minArea) minArea = area;
            }
        }
    }
    return minArea;
}
