#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>

// -----------------------------------------------------------------------------
//  Point structure – unchanged
// -----------------------------------------------------------------------------
struct Point {
    double x, y;
};

// -----------------------------------------------------------------------------
//  Cross product (b-a) × (c-a) – inline for speed
// -----------------------------------------------------------------------------
inline double Cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

// -----------------------------------------------------------------------------
//  Convex hull – Graham scan, O(n log n)
//  The implementation is identical in result to the original code but
//  eliminates unnecessary function objects, copies and performs a move
//  to avoid a final re‑allocation.
// -----------------------------------------------------------------------------
void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();

    // Trivial cases
    if (n < 3) {
        hull = points;
        return;
    }

    // Copy and sort once (lexicographic order)
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // Reserve capacity → avoid reallocations during hull construction
    std::vector<Point> ans;
    ans.reserve(2 * n);

    // Build lower hull
    for (const Point& pt : sorted) {
        while (ans.size() >= 2 &&
               Cross(ans[ans.size() - 2], ans[ans.size() - 1], pt) <= 0.0)
            ans.pop_back();
        ans.push_back(pt);
    }

    // Build upper hull
    const std::size_t lowerSize = ans.size();
    for (std::size_t i = n - 1; i > 0; --i) {
        const Point& pt = sorted[i - 1];
        while (ans.size() > lowerSize + 1 &&
               Cross(ans[ans.size() - 2], ans[ans.size() - 1], pt) <= 0.0)
            ans.pop_back();
        ans.push_back(pt);
    }

    // The last point is the same as the first one – discard it
    if (!ans.empty())
        ans.pop_back();

    // Fast transfer to the user supplied vector
    hull = std::move(ans);
}
