#pragma once
#include <vector>
#include <cstring>      // for memcpy
#include <omp.h>        // OpenMP

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row‑major. x and b have N elements.
   Example:

     input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
     output: x=[3, 1, 2]
*/
void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // Allocate plain arrays for faster access.
    std::vector<double> A_tmp(N * N);
    std::vector<double> b_tmp(N);

    // Copy input data (faster than element‑by‑element copy).
    std::memcpy(A_tmp.data(), A.data(), N * N * sizeof(double));
    std::memcpy(b_tmp.data(),  b.data(),  N * sizeof(double));

    // Gaussian elimination – forward elimination.
    for (size_t i = 0; i < N - 1; ++i)
    {
        double pivot = A_tmp[i * N + i];
        if (pivot == 0.0)  // singular matrix – leave result undefined
            return;

        double invPivot = 1.0 / pivot;

        // Parallelize over rows below the pivot.
        #pragma omp parallel for schedule(static)
        for (ptrdiff_t j = (ptrdiff_t)i + 1; j < (ptrdiff_t)N; ++j)
        {
            double factor = A_tmp[j * N + i] * invPivot;
            // update row j
            double* rowJ = A_tmp.data() + j * N;
            const double* rowI = A_tmp.data() + i * N;
            for (size_t k = i; k < N; ++k)
                rowJ[k] -= factor * rowI[k];
            b_tmp[j] -= factor * b_tmp[i];
        }
    }

    // Back substitution.
    for (ptrdiff_t i = (ptrdiff_t)N - 1; i >= 0; --i)
    {
        double sum = 0.0;
        double* rowi = A_tmp.data() + i * N;
        for (size_t j = i + 1; j < N; ++j)
            sum += rowi[j] * x[j];
        x[i] = (b_tmp[i] - sum) / rowi[i];
    }
}
