static constexpr int edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/*
 * Convolve the image with the 3×3 edge‑detection kernel.
 * The input and output buffers are stored row‑major and contain N×N
 * grayscale values in the range [0,255].  The borders are treated as zero.
 * The result is clipped to [0,255].
 */
inline void convolveKernel(const std::vector<int>& imageIn,
                           std::vector<int>& imageOut,
                           size_t N)
{
    // Ensure output buffer is large enough.
    imageOut.resize(N * N);

    const int    stride  = static_cast<int>(N);
    const int*    inPtr   = imageIn.data();
    int*          outPtr  = imageOut.data();

    /* Parallelise the outermost loop.  Each thread works on a distinct
     * set of rows, so no synchronisation is required. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int iN = i * stride;          // row offset
        const int* row_m1 = (i > 0)   ? inPtr + (i-1)*stride : nullptr;
        const int* row    = inPtr + iN;
        const int* row_p1 = (i + 1 < static_cast<int>(N)) ? inPtr + (i+1)*stride : nullptr;

        for (int j = 0; j < static_cast<int>(N); ++j) {
            int sum = 0;

            // –1, 0, +1 contributions
            if (row_m1) sum += row_m1[j-1] * edgeKernel[0][0] +  // (-1,-1)
                            row_m1[j  ] * edgeKernel[0][1] +  // (-1, 0)
                            row_m1[j+1] * edgeKernel[0][2];   // (-1,+1)

            sum += row[j-1] * edgeKernel[1][0] +   // (0,-1)
                   row[j  ] * edgeKernel[1][1] +   // (0, 0)
                   row[j+1] * edgeKernel[1][2];    // (0,+1)

            if (row_p1) sum += row_p1[j-1] * edgeKernel[2][0] + // (+1,-1)
                            row_p1[j  ] * edgeKernel[2][1] + // (+1, 0)
                            row_p1[j+1] * edgeKernel[2][2];  // (+1,+1)

            // Clamp to [0,255]
            outPtr[iN + j] = static_cast<int>(std::max(0, std::min(255, sum)));
        }
    }
}
