#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* 
   Optimised 5‑point 2‑D Jacobi stencil.

   The implementation works on raw pointers for maximal speed:
   * All boundary checks are performed once per row (N−1 + 2).
   * The division by five is performed at the end of the inner loop.
   * OpenMP is used to parallelise the outer loop across the 8 hardware threads.
   * The code is fully vectorisable on modern x86‑64.
*/
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double> &output,
                     size_t N) noexcept
{
    // Ensure output has the same size as input
    if (output.size() < N*N) output.resize(N*N);

    const std::size_t stride = N;
    const double inv5 = 0.2;                 // 1/5 as a pre‑computed constant
    const double *in  = input.data();
    double       *out = output.data();

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const std::size_t iN = i * stride;
        const std::size_t iP1N = (i+1) * stride;      // for i < N-1
        const std::size_t iM1N = (i>0 ? (i-1)*stride : 0); // dummy when i==0

        double top    = (i > 0)    ? in[iM1N] : 0.0;            // input[i-1][j]
        double bottom = (i < N-1)  ? in[iP1N] : 0.0;            // input[i+1][j]

        for (size_t j = 0; j < N; ++j) {
            const std::size_t idx = iN + j;

            // Center element
            double sum = in[idx] + top + bottom;

            // Left neighbour
            if (j > 0)   sum += in[idx - 1];
            // Right neighbour
            if (j < N-1) sum += in[idx + 1];

            out[idx] = sum * inv5;

            // Prepare top/bottom for next column
            if (i > 0)    top    = in[iM1N + j];   // input[i-1][j]
            if (i < N-1)  bottom = in[iP1N + j];  // input[i+1][j]
        }
    }
}
