#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Every cell becomes 1 iff it has exactly one neighboring cell that is 1
   (orthogonal neighbors only).  Input and output are N×N in row‑major order.
   The implementation performs the neighbor summation in four separate
   passes and then applies the XOR rule in a compact, cache‑friendly loop.
   OpenMP is used to parallelise the work across all 8 threads. */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     size_t N) noexcept
{
    const size_t total = N * N;
    std::vector<int> neigh(total, 0);                 // temporary neighbor counts

    /* 1. Add north neighbour contributions */
    #pragma omp parallel for schedule(static)
    for (size_t i = 1; i < N; ++i) {
        size_t base   = i   * N;
        size_t north  = (i-1) * N;
        for (size_t j = 0; j < N; ++j)
            if (input[north + j]) neigh[base + j] += 1;
    }

    /* 2. Add south neighbour contributions */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N-1; ++i) {
        size_t base   = i   * N;
        size_t south  = (i+1) * N;
        for (size_t j = 0; j < N; ++j)
            if (input[south + j]) neigh[base + j] += 1;
    }

    /* 3. Add west neighbour contributions */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t base = i * N;
        for (size_t j = 1; j < N; ++j)
            if (input[base + j-1]) neigh[base + j] += 1;
    }

    /* 4. Add east neighbour contributions */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t base = i * N;
        for (size_t j = 0; j < N-1; ++j)
            if (input[base + j+1]) neigh[base + j] += 1;
    }

    /* Final XOR stage: set output to 1 iff count == 1 */
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < total; ++idx)
        output[idx] = (neigh[idx] == 1) ? 1 : 0;
}
