#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/*--------------------------------------------------------------------
   In‑place radix‑2 Cooley–Tukey FFT/ inverse FFT
   Returns the exact same results as the original implementation
   but offers a substantial speedup on modern hosts.
--------------------------------------------------------------------*/
static inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N < 2) return;
    // compute bit reversal pattern once
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t r = i;
        r = ((r & 0xaaaaaaaa) >> 1) | ((r & 0x55555555) << 1);
        r = ((r & 0xcccccccc) >> 2) | ((r & 0x33333333) << 2);
        r = ((r & 0xf0f0f0f0) >> 4) | ((r & 0x0f0f0f0f) << 4);
        r = ((r & 0xff00ff00) >> 8) | ((r & 0x00ff00ff) << 8);
        r = (r >> 16) | (r << 16);
        rev[i] = r >> (32 - logN);
    }

    // bit‑reversal permutation
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = rev[i];
        if (j > i)
            std::swap(x[i], x[j]);
    }

    // Cooley–Tukey
    for (std::size_t s = 1; s <= logN; ++s)
    {
        const std::size_t m = 1ULL << s;               // stage length
        const std::size_t m2 = m >> 1;                 // half
        const double theta = -M_PI / static_cast<double>(m2);
        const std::complex<double> wm = std::exp(std::complex<double>(0.0, theta));

        for (std::size_t k = 0; k < N; k += m)
        {
            std::complex<double> w(1.0, 0.0);
#pragma omp parallel for schedule(static) if(m2>32)
            for (std::size_t j = 0; j < m2; ++j)
            {
                std::size_t a = k + j;
                std::size_t b = a + m2;
                std::complex<double> t = w * x[b];
                x[b] = x[a] - t;
                x[a] += t;
            }
            w *= wm;
        }
    }
}

/* Inverse FFT – same as forward FFT on conjugated values, then conjugate again
   and divide by N. */
inline void ifft(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
