#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N < 2) {
        // nothing to do
        std::for_each(x.begin(), x.end(),
                      [](std::complex<double>& v){ v = std::conj(v); });
        return;
    }

    /*---------- 1. Iterative radix‑2 Cooley‑Tukey FFT ---------*/

    // Pre‑compute bit‑reversal permutation table
    std::size_t logN = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t r = 0, t = i;
        for (std::size_t j = 0; j < logN; ++j) {
            r = (r << 1) | (t & 1);
            t >>= 1;
        }
        rev[i] = r;
    }

    // Bit‑reversal permutation
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i) std::swap(x[i], x[j]);
    }

    // Main FFT loop (iterative, radix‑2)
    for (std::size_t s = 1; s <= logN; ++s) {
        std::size_t m = 1UL << s;            // current stage size
        std::size_t mh = m >> 1;            // half step
        const double theta = -M_PI / mh;    // negative angle for forward FFT
        const double wlen_real = std::cos(theta);
        const double wlen_imag = std::sin(theta);

        // Parallelise over outer butterfly groups
#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < mh; ++k) {
            // Pre‑compute twiddle factor for this k
            double w_real = 1.0;
            double w_imag = 0.0;
            for (std::size_t j = 0; j < mh; ++j) {
                const std::size_t idx1 = k + j * m;
                const std::size_t idx2 = idx1 + mh;

                std::complex<double> t = x[idx1] - x[idx2];
                x[idx1] += x[idx2];
                // multiply by twiddle
                double tr = t.real() * w_real - t.imag() * w_imag;
                double ti = t.real() * w_imag + t.imag() * w_real;
                x[idx2] = std::complex<double>(tr, ti);

                // advance twiddle factor
                double tmp = w_real * wlen_real - w_imag * wlen_imag;
                w_imag = w_real * wlen_imag + w_imag * wlen_real;
                w_real = tmp;
            }
        }
    }

    /*---------- 2. Conjugation ---------*/

#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]);
    }
}
