/* Return the index of the value in the vector x that is closest to the math
   constant PI. The result is identical to the original implementation.
   The function uses OpenMP to parallelise the search.
--------------------------------------------------------------------------*/
size_t findClosestToPi(std::vector<double> const& x) {
    // Ensure we have at least one element (as the original code assumes).
    if (x.empty())
        return 0;   // Undefined behavior for empty input; return 0 for safety.

    const double pi = M_PI;
    const std::size_t n = x.size();

    // Struct to hold the current best index and its distance (used for parallel reduction).
    struct Best {
        std::size_t idx;
        double dist;
    } local_best{0, std::numeric_limits<double>::max()};

    // Parallel scan: each thread finds its local best, then we combine.
    #pragma omp parallel
    {
        Best thread_best{0, std::numeric_limits<double>::max()};
        #pragma omp for nowait
        for (std::size_t i = 0; i < n; ++i) {
            const double d = std::abs(x[i] - pi);
            if (d < thread_best.dist) {
                thread_best.dist = d;
                thread_best.idx   = i;
            }
        }

        #pragma omp critical
        {
            if (thread_best.dist < local_best.dist) {
                local_best = thread_best;   // Update global best.
            }
        }
    }

    // In case of ties the first occurring index is required.
    // Since the parallel section may select a later index in case of equal distances,
    // perform a single full linear pass to guarantee the earliest occurrence.
    std::size_t best_idx = local_best.idx;
    double best_dist = local_best.dist;
    for (std::size_t i = 0; i < n; ++i) {
        double d = std::abs(x[i] - pi);
        if (d < best_dist) {
            best_dist = d;
            best_idx = i;
        } else if (d == best_dist && i < best_idx) {
            best_idx = i;
        }
    }
    return best_idx;
}
