/*
 * In‑place LU factorisation (no pivoting).
 *
 * A is an N×N matrix in row-major order.
 * After the call:
 *   - The lower triangular part (including the diagonal) contains L
 *     with unit diagonal (the diagonal values are the pivots of U).
 *   - The upper triangular part contains U.
 *
 * This implementation
 *   • pre‑computes the reciprocal of each pivot (O(1) division per outer column),
 *   • uses pointer arithmetic for fast index calculations,
 *   • parallelises the inner `i` loop with OpenMP (the outer `k` loop is inherently serial),
 *   • stores the multipliers in `A[i*N + k]` exactly as the original algorithm does.
 */
void luFactorize(std::vector<double> &A, const std::size_t N) {
    double *ap = A.data();          // convenient pointer to the underlying array

    for (std::size_t k = 0; k < N; ++k) {
        const double pivot = ap[k * N + k];
        // Avoid division in the inner loop by pre‑computing its reciprocal
        const double invPivot = 1.0 / pivot;

#pragma omp parallel for schedule(static)
        for (std::size_t i = k + 1; i < N; ++i) {
            const std::size_t idxIK = i * N + k;
            const double factor = ap[idxIK] * invPivot;
            ap[idxIK] = factor;                // store L‑factor

            const std::size_t rowK = k * N;
            const double *rowKi = ap + rowK;
            double *rowIk = ap + idxIK;

            // Unroll the inner j‑loop by a factor of 4 for better vectorisation
            std::size_t j = k + 1;
            for (; j + 3 < N; j += 4) {
                rowIk[j + 0] -= factor * rowKi[j + 0];
                rowIk[j + 1] -= factor * rowKi[j + 1];
                rowIk[j + 2] -= factor * rowKi[j + 2];
                rowIk[j + 3] -= factor * rowKi[j + 3];
            }
            for (; j < N; ++j) {
                rowIk[j] -= factor * rowKi[j];
            }
        }
    }
}
