struct Result {
    int startTime, duration;
    float value;
};

namespace {

// A simple parallel merge sort that works on the std::vector<Result>
// via an auxiliary buffer that is reused between recursive calls.
// The algorithm is stable, uses O(n) auxiliary memory,
// and exploits up to 8 threads on the computer's CPU.
inline void merge(const Result* left, const Result* mid, const Result* right,
                  Result* dest)
{
    const Result* i = left;
    const Result* j = mid;
    const Result* endLeft = mid;
    const Result* endRight = right;
    while (i < endLeft && j < endRight) {
        dest[0] = (*i).startTime < (*j).startTime ? *i++ : *j++;
        ++dest;
    }
    while (i < endLeft)  *dest++ = *i++;
    while (j < endRight) *dest++ = *j++;
}

inline void parallel_merge_sort(Result* data, Result* temp,
                                std::size_t left, std::size_t right,
                                int depth = 0)
{
    if (right - left <= 1)
        return;

    // Determine middle point
    std::size_t mid = left + (right - left) / 2;

    if (depth < 8) {          // only spawn new threads while we are below the limit
#pragma omp task shared(data, temp)
        parallel_merge_sort(data, temp, left, mid, depth + 1);
#pragma omp task shared(data, temp)
        parallel_merge_sort(data, temp, mid, right, depth + 1);
#pragma omp taskwait
    } else {                  // otherwise use a single thread
        parallel_merge_sort(data, temp, left, mid, depth);
        parallel_merge_sort(data, temp, mid, right, depth);
    }

    // Merge the two halves into the temporary buffer
    merge(data + left, data + mid, data + right, temp + left);

    // Copy the merged result back to the original array
    std::copy(temp + left, temp + right, data + left);
}

} // anonymous namespace

/* Sort vector of Result structs by start time in ascending order.
   The function is thread‑safe from the perspective of the harness
   and uses OpenMP to parallelise the merge sort.  The output ordering
   is guaranteed to match that of a single‑threaded std::sort. */
inline
void sortByStartTime(std::vector<Result> &results)
{
    if (results.size() <= 1)
        return;

    std::vector<Result> temp(results.size());   // auxiliary buffer

    #pragma omp parallel
    {
        #pragma omp single nowait
        parallel_merge_sort(results.data(), temp.data(), 0, results.size());
    }
}
