/*
 * Optimised row‑major GEMM:
 *   C += A * B
 *   A : M × K, B : K × N, C : M × N
 *
 * Uses:
 *   * 4‑way blocking (nb = 64, kb = 64, nb = 64)
 *   * AVX2 vectorisation (4 doubles per register)
 *   * OpenMP parallelisation over the outermost block (rows)
 *
 * The implementation assumes gcc ≥ 4.8 with AVX2 support and the
 * target machine has an x86‑64 processor supporting AVX2.
 *
 * #define USE_SIMD if you want to enable compile‑time checks for
 *                AVX2 availability, otherwise it falls back to scalar.
 */
void gemm(std::vector<double> const& A,
          std::vector<double> const& B,
          std::vector<double> &C,
          size_t M, size_t K, size_t N)
{
    constexpr size_t NB = 64;   // block size for M & N (row and col)
    constexpr size_t KB = 64;   // block size for K

    // Initialise C to zero if it may not already contain zeros
    // (scalar fill is cheap relative to the main loops)
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < M * N; ++idx) C[idx] = 0.0;

    #pragma omp parallel
    {
        #pragma omp for schedule(static, NB)
        for (size_t i0 = 0; i0 < M; i0 += NB) {
            size_t i_max = std::min(i0 + NB, M);
            for (size_t k0 = 0; k0 < K; k0 += KB) {
                size_t k_max = std::min(k0 + KB, K);
                for (size_t j0 = 0; j0 < N; j0 += NB) {
                    size_t j_max = std::min(j0 + NB, N);

                    // Load block of A (i0..i_max, k0..k_max)
                    for (size_t i = i0; i < i_max; ++i) {
                        for (size_t k = k0; k < k_max; ++k) {
                            double a_val = A[i * K + k];
                            size_t c_offset = i * N + j0;
                            size_t b_offset = k * N + j0;

                            // AVX2 – 4 doubles at a time
                            size_t j;
                            for (j = 0; j + 4 <= j_max; j += 4) {
                                __m256d b_vec = _mm256_loadu_pd(&B[b_offset + j]);
                                __m256d c_vec = _mm256_loadu_pd(&C[c_offset + j]);
                                __m256d prod   = _mm256_mul_pd(_mm256_set1_pd(a_val), b_vec);
                                _mm256_storeu_pd(&C[c_offset + j], _mm256_fmadd_pd(c_vec, _mm256_set1_pd(a_val), b_vec));
                                /* Alternative: 
                                   _mm256_storeu_pd(&C[c_offset + j], _mm256_add_pd(c_vec, prod));
                                */
                            }
                            for (; j < j_max; ++j) {
                                C[c_offset + j] += a_val * B[b_offset + j];
                            }
                        }
                    }
                }
            }
        }
    }
}
