struct Point {
    double x, y;
};

namespace {
    // squared distance – avoids sqrt in all inner loops
    static inline double sqdist(const Point& a, const Point& b) {
        double dx = a.x - b.x;
        double dy = a.y - b.y;
        return dx * dx + dy * dy;
    }

    // helper for the divide‑and‑conquer algorithm
    static void closestRec(std::vector<Point>& pts, size_t l,
                           size_t r, std::vector<Point>& tmp,
                           double& best) {
        if (r - l <= 3) {                     // brute force
            for (size_t i = l; i < r; ++i)
                for (size_t j = i + 1; j < r; ++j)
                    best = std::min(best, sqdist(pts[i], pts[j]));
            std::sort(pts.begin() + l, pts.begin() + r,
                      [](const Point& a, const Point& b){ return a.y < b.y; });
            return;
        }

        size_t m = (l + r) / 2;
        double midx = pts[m].x;
        closestRec(pts, l, m, tmp, best);
        closestRec(pts, m, r, tmp, best);

        // merge by y
        std::merge(pts.begin() + l, pts.begin() + m,
                   pts.begin() + m, pts.begin() + r,
                   tmp.begin(), [](const Point& a, const Point& b){ return a.y < b.y; });
        std::copy(tmp.begin(), tmp.begin() + (r - l), pts.begin() + l);

        // strip: points within sqrt(best) of the median line
        size_t sz = 0;
        for (size_t i = l; i < r; ++i) {
            if (std::abs(pts[i].x - midx) < std::sqrt(best))
                tmp[sz++] = pts[i];
        }

        // compare each point to next up to 7 neighbors
        for (size_t i = 0; i < sz; ++i) {
            for (size_t j = i + 1; j < sz && (tmp[j].y - tmp[i].y) < std::sqrt(best); ++j)
                best = std::min(best, sqdist(tmp[i], tmp[j]));
        }
    }
}

double closestPair(const std::vector<Point>& points) {
    size_t n = points.size();
    if (n < 2) return 0.0;

    // copy and sort by x once
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> tmp(n);
    double best = std::numeric_limits<double>::max();

    // Parallel divide‑and‑conquer: split into chunks that can be processed independently.
    // We limit concurrency to the number of available threads.
    int maxThreads = omp_get_max_threads();
    std::vector<double> threadBest(maxThreads, std::numeric_limits<double>::max());

    #pragma omp parallel
    {
        int id = omp_get_thread_num();
        size_t chunk = (n + maxThreads - 1) / maxThreads;
        size_t start = id * chunk;
        if (start >= n) return;
        size_t end   = std::min(start + chunk, n);

        // each thread works on its slice – we still need to sort by y within the slice
        std::vector<Point> local(pts.begin() + start, pts.begin() + end);
        std::sort(local.begin(), local.end(),
                  [](const Point& a, const Point& b){ return a.y < b.y; });

        for (size_t i = 0; i < local.size() - 1; ++i)
            for (size_t j = i + 1; j < local.size(); ++j)
                threadBest[id] = std::min(threadBest[id],
                                          sqdist(local[i], local[j]));

        #pragma omp barrier
    }

    // fold per‑thread results
    for (double b : threadBest) best = std::min(best, b);

    // final global sweep for cross‑slice pairs using the full divide‑and‑conquer
    closestRec(pts, 0, n, tmp, best);

    return std::sqrt(best);
}
