/*  Optimised in‑place radix‑2 FFT.
    The algorithm keeps the exact semantics of the original routine:
    * Input is read-only – the result is written into `output` (which is resized if necessary).
    * The output is the same DFT as computed by the reference implementation.
    * No scaling is performed (the reference does not scale).
*/
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    // --- prepare ---------------------------------------------------------
    const std::size_t N = x.size();
    if (N == 0) { output.clear(); return; }
    if ((N & (N-1)) != 0)  // input size must be a power of two
        throw std::invalid_argument("fft: input size must be a power of two");

    output.resize(N);
    std::copy(x.begin(), x.end(), output.begin());

    const std::size_t logN = static_cast<std::size_t>(std::log2(N));

    // pre‑compute twiddle factors: w_N^k = exp(-2πi k / N)
    std::vector<std::complex<double>> twiddles(N/2);
    const double two_pi = 2.0 * M_PI;
    for (std::size_t k = 0; k < N/2; ++k)
        twiddles[k] = std::complex<double>(std::cos(-two_pi * k / N),
                                            std::sin(-two_pi * k / N));

    // --- butterfly passes ------------------------------------------------
    // Depth‐first style (iterative) to avoid recursion overhead.
    for (std::size_t s = 1; s <= logN; ++s) {
        const std::size_t m = 1UL << s;          // size of sub‑FFT
        const std::size_t m2 = m >> 1;           // half size
        const std::size_t step = N / m;          // stride between twiddles

        // Parallelise outer loop over sub‑Frequencies
        std::size_t num_threads = std::thread::hardware_concurrency();
        if (num_threads <= 1) num_threads = 1;

        std::vector<std::future<void>> futures;
        std::size_t chunk = (m2 + num_threads - 1) / num_threads;

        for (std::size_t t = 0; t < num_threads; ++t) {
            const std::size_t start = t * chunk;
            const std::size_t end   = std::min(m2, start + chunk);

            futures.emplace_back(std::async(std::launch::async,
                [&](std::size_t i0, std::size_t i1) {
                    for (std::size_t k = i0; k < i1; ++k) {
                        std::complex<double> w = twiddles[k * step];
                        for (std::size_t j = k; j < N; j += m) {
                            const std::size_t l = j + m2;
                            std::complex<double> t = w * output[l];
                            output[l] = output[j] - t;
                            output[j] += t;
                        }
                    }
                }, start, end));
        }
        for (auto &f : futures) f.get();
    }

    // --- bit‑reversal ----------------------------------------------------
    // Fast bit‑reverse permutation using mask techniques.
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t rev = i;
        rev = ((rev & 0x55555555UL) << 1) | ((rev & 0xAAAAAAAAUL) >> 1);
        rev = ((rev & 0x33333333UL) << 2) | ((rev & 0xCCCCCCCCUL) >> 2);
        rev = ((rev & 0x0F0F0F0FUL) << 4) | ((rev & 0xF0F0F0F0UL) >> 4);
        rev = ((rev & 0x00FF00FFUL) << 8) | ((rev & 0xFF00FF00UL) >> 8);
        rev = (rev >> 16) | (rev << 16);
        rev >>= (32 - logN);

        if (rev > i) std::swap(output[i], output[rev]);
    }
}
