#pragma once
#include <vector>
#include <numeric>
#include <omp.h>

/*
 * Parallel stable merge sort – preserved ordering of equal elements.
 */
static void merge(const std::vector<size_t>& src, std::vector<size_t>& dst,
                  size_t left, size_t mid, size_t right, const std::vector<float>& x)
{
    size_t i = left, j = mid, k = left;
    while (i < mid && j < right) {
        if (x[src[i]] < x[src[j]]) {
            dst[k++] = src[i++];
        } else if (x[src[i]] == x[src[j]] && i < j) {   // preserve stability
            dst[k++] = src[i++];
        } else {
            dst[k++] = src[j++];
        }
    }
    while (i < mid) dst[k++] = src[i++];
    while (j < right) dst[k++] = src[j++];
}

static void merge_sort(std::vector<size_t>& src,
                       std::vector<size_t>& dst,
                       size_t left, size_t right,
                       const std::vector<float>& x,
                       size_t depth = 0)
{
    if (right - left <= 1) {            // base case
        if (&src != &dst) dst[left] = src[left];
        return;
    }

    size_t mid = (left + right) / 2;

    // Parallel recursion using OpenMP tasks
    #pragma omp task shared(src,dst,x) if(depth < 4)
    merge_sort(src, dst, left, mid, x, depth + 1);
    #pragma omp task shared(src,dst,x) if(depth < 4)
    merge_sort(src, dst, mid, right, x, depth + 1);
    #pragma omp taskwait

    // Merge results from src into dst
    merge(src, dst, left, mid, right, x);
}

/* Original function signature */
void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_)
{
    const size_t n = x.size();
    ranks_.resize(n);
    std::vector<size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);
    std::vector<size_t> temp(n);

#pragma omp parallel
    {
#pragma omp single
        merge_sort(indices, temp, 0, n, x);
    }

    /* If merge_sort wrote to temp (which it does), copy back if needed */
    if (temp[0] != indices[0]) std::swap(indices, temp);

    for (size_t i = 0; i < n; ++i) {
        ranks_[indices[i]] = i;
    }
}
